review_text:
Neredeyse hiç yeni bir şey yok aslında;

Araçlar ve satın alma menüsü yeni, grafikler, sesler ve kullanıcı arayüzü yeni, ancak bunların hiçbiri değişimi haklı çıkaracak kadar değil. Oyun, selefine göre önemli ölçüde daha az dengeli ve önemli ölçüde daha az cilalı.

Ve evet, bu daha önce yapıldı, ancak valve ne kadar büyür ve ne kadar çok para kazanırsa, bu o kadar az kabul edilebilir hale geliyor...

yazcak bişey bulamadım alın size unity korku oyunu için c#  movement script kodu

using UnityEngine;

[RequireComponent(typeof(CharacterController))]
public class PlayerMovement : MonoBehaviour
{
    [Header("Hareket Ayarları")]
    public float walkSpeed = 4f; // Korku oyunu için biraz yavaşlattım (daha gergin)
    public float runSpeed = 8f;
    public float crouchSpeed = 2f;
    public float jumpPower = 6f;
    public float gravity = 20f;

    [Header("Bakış Ayarları")]
    public Camera playerCamera;
    public float lookSpeed = 2f;
    public float lookXLimit = 75f; // Daha geniş bakış açısı

    [Header("Eğilme Ayarları")]
    public float defaultHeight = 2f;
    public float crouchHeight = 1f;
    public float crouchCameraY = 0.5f; // Eğilince kamera nereye insin?
    public float defaultCameraY = 0.8f; // Normalde kamera nerede?

    private Vector3 moveDirection = Vector3.zero;
    private float rotationX = 0;
    private CharacterController characterController;

    private bool isCrouching = false;
    private bool canMove = true;

    void Start()
    {
        characterController = GetComponent<CharacterController>();

        // Fareyi kilitle ve gizle
        Cursor.lockState = CursorLockMode.Locked;
        Cursor.visible = false;
    }

    void Update()
    {
        // 1. Hareket Yönlerini Hesapla
        Vector3 forward = transform.TransformDirection(Vector3.forward);
        Vector3 right = transform.TransformDirection(Vector3.right);

        // Durum Kontrolleri
        bool isRunning = Input.GetKey(KeyCode.LeftShift) && !isCrouching;
        float curSpeedX = canMove ? (isCrouching ? crouchSpeed : (isRunning ? runSpeed : walkSpeed)) * Input.GetAxis("Vertical") : 0;
        float curSpeedY = canMove ? (isCrouching ? crouchSpeed : (isRunning ? runSpeed : walkSpeed)) * Input.GetAxis("Horizontal") : 0;

        float movementDirectionY = moveDirection.y;
        moveDirection = (forward * curSpeedX) + (right * curSpeedY);

        // 2. Zıplama ve Yerçekimi (Senin Hatanın Çözümü Burası)
        if (characterController.isGrounded)
        {
            // GetButtonDown: Sadece ilk basışta tetiklenir, basılı tutunca zıplamaz.
            if (Input.GetButtonDown("Jump") && canMove && !isCrouching)
            {
                moveDirection.y = jumpPower;
            }
            else
            {
                // Yerdeyken küçük bir baskı uygula ki merdivenlerde titreme yapmasın
                moveDirection.y = -2f;
            }
        }
        else
        {
            // Havadaysa yerçekimi uygula
            moveDirection.y = movementDirectionY - (gravity * Time.deltaTime);
        }

        // 3. Eğilme Mekaniği (C Tuşu Daha Standarttır ama R'de kalabilir)
        if (Input.GetKey(KeyCode.C) && canMove) 
        {
            isCrouching = true;
            characterController.height = crouchHeight;
            // Kamerayı yavaşça aşağı indir (Yumuşak geçiş için)
            Vector3 camPos = playerCamera.transform.localPosition;
            camPos.y = Mathf.Lerp(camPos.y, crouchCameraY, Time.deltaTime * 10);
            playerCamera.transform.localPosition = camPos;
        }
        else
        {
            // Ayağa kalkarken kafanın üstünde bir şey var mı kontrolü eklenebilir ama basit tutalım:
            isCrouching = false;
            characterController.height = defaultHeight;
            Vector3 camPos = playerCamera.transform.localPosition;
            camPos.y = Mathf.Lerp(camPos.y, defaultCameraY, Time.deltaTime * 10);
            playerCamera.transform.localPosition = camPos;
        }

        // 4. Karakteri Hareket Ettir
        characterController.Move(moveDirection * Time.deltaTime);

        // 5. Kamera Bakışı
        if (canMove)
        {
            rotationX += -Input.GetAxis("Mouse Y") * lookSpeed;
            rotationX = Mathf.Clamp(rotationX, -lookXLimit, lookXLimit);
            playerCamera.transform.localRotation = Quaternion.Euler(rotationX, 0, 0);
            transform.rotation *= Quaternion.Euler(0, Input.GetAxis("Mouse X") * lookSpeed, 0);
        }
    }
}
